INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '大吉', '努力が実を結ぶ最高の時。迷わず大きく一歩を踏み出そう。', '{"仕事": "重要な案件で評価される。昇進・抜擢の芽あり。", "学業": "理解が一気に深まる。難問もスッと解ける。", "試験": "実力を出し切れる。手応えそのままの好結果。", "対人": "頼れる仲間と出会える。協力で成果が倍増。"}', '{"ラッキーアイテム": "万年筆", "ラッキーカラー": "紺", "吉方位": "北", "開運数字": "3"}');
