INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '大吉', '追い風が吹いている。挑戦すればするほど道が開ける。', '{"仕事": "難局を任され、見事にさばいて株を上げる。", "学業": "苦手分野が腑に落ちる転機の日。", "試験": "本番に強い日。緊張すら追い風になる。", "対人": "良き師・メンターとの縁。教えを素直に受けて吉。"}', '{"ラッキーアイテム": "青いノート", "ラッキーカラー": "緑", "吉方位": "南", "開運数字": "8"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '大吉', '周囲の信頼が一気に集まる日。任された仕事を堂々とこなそう。', '{"仕事": "成果が数字に表れる。継続が報われる。", "学業": "学んだ内容がしっかり定着する。復習が効く。", "試験": "ケアレスミスが出ない。落ち着いて全問正解を狙える。", "対人": "チームの中心として信頼される。"}', '{"ラッキーアイテム": "観葉植物", "ラッキーカラー": "金", "吉方位": "西", "開運数字": "1"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '大吉', '視界がひらける一日。長年の目標に手が届きはじめる。', '{"仕事": "新しい役割が舞い込む。受けて正解。", "学業": "良い参考書・先生に出会える。素直に取り入れて吉。", "試験": "合格圏に手が届く。自信を持って臨もう。", "対人": "感謝を伝えると関係がさらに深まる。"}', '{"ラッキーアイテム": "腕時計", "ラッキーカラー": "青", "吉方位": "北東", "開運数字": "5"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '大吉', 'ひらめきと行動が噛み合う。アイデアを即実行に移して吉。', '{"仕事": "上司の後押しを得て前進。遠慮は不要。", "学業": "発表・課題で高評価。準備が報われる。", "試験": "時間配分が完璧。余裕を持って解き切れる。", "対人": "紹介・推薦の話が舞い込む。"}', '{"ラッキーアイテム": "名刺入れ", "ラッキーカラー": "橙", "吉方位": "南東", "開運数字": "9"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '大吉', '実力以上の成果が出る好機。遠慮せず前へ。', '{"仕事": "段取り上手が光る日。周囲を巻き込んで大成功。", "学業": "新しい学習法がハマる。効率が跳ね上がる。", "試験": "面接・口頭試問で好印象。言葉がスラスラ出る。", "対人": "対立も対話で好転。歩み寄りが実を結ぶ。"}', '{"ラッキーアイテム": "緑茶", "ラッキーカラー": "紫", "吉方位": "南西", "開運数字": "2"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '大吉', '縁と運が味方する。大きな決断ほど良い結果につながる。', '{"仕事": "長期の取り組みが実を結ぶ。次の目標も見えてくる。", "学業": "知的好奇心が原動力に。学ぶほど楽しくなる。", "試験": "第一志望に届く運気。強気の出願が吉。", "対人": "人脈が次のチャンスを運んでくる。"}', '{"ラッキーアイテム": "ブックカバー", "ラッキーカラー": "銀", "吉方位": "北西", "開運数字": "6"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '中吉', 'good な流れ。焦らず着実に進めれば成果は十分。', '{"仕事": "担当業務が順調。報連相を丁寧にすると更に良い。", "学業": "予習が効く。理解の土台が固まる。", "試験": "見直しでミスを拾える。最後まで気を抜かないで。", "対人": "素直な相談が良縁を呼ぶ。"}', '{"ラッキーアイテム": "鉛筆", "ラッキーカラー": "桜色", "吉方位": "北", "開運数字": "4"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '中吉', 'やるべきことが明確になる日。一つずつ片付けよう。', '{"仕事": "改善提案が好印象。小さな一言が評価される。", "学業": "ノートの取り方を変えると伸びる。", "試験": "得意分野で確実に点を稼げる。", "対人": "感謝の一言で関係が温まる。"}', '{"ラッキーアイテム": "印鑑", "ラッキーカラー": "山吹色", "吉方位": "東", "開運数字": "11"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '中吉', '小さな成功が自信に変わる。勢いを大切に。', '{"仕事": "締切に余裕を持って臨めそう。", "学業": "適度な休憩で集中が続く。", "試験": "時間配分を意識すれば好結果。", "対人": "聞き役に回ると信頼が増す。"}', '{"ラッキーアイテム": "しおり", "ラッキーカラー": "藍", "吉方位": "南", "開運数字": "21"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '中吉', '準備が整いつつある。あと一歩の踏み込みが鍵。', '{"仕事": "同僚との連携がうまくいく。", "学業": "苦手も少しずつ前進。焦らないで。", "試験": "基本問題を落とさなければ合格圏。", "対人": "仲間の助言が役立つ。"}', '{"ラッキーアイテム": "白いハンカチ", "ラッキーカラー": "若草色", "吉方位": "西", "開運数字": "24"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '中吉', '周囲の助けを借りると一気に進む。遠慮しないで。', '{"仕事": "段取りを見直すと効率アップ。", "学業": "友人との勉強会が好結果。", "試験": "前日の早寝が効く。", "対人": "小さな約束を守ると評価が上がる。"}', '{"ラッキーアイテム": "万年筆", "ラッキーカラー": "紺", "吉方位": "北東", "開運数字": "3"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '中吉', '地道な作業が報われ始める。継続が吉。', '{"仕事": "新しいツールが役立つ。試して吉。", "学業": "基礎の確認が後で効いてくる。", "試験": "落ち着けば実力どおり出せる。", "対人": "笑顔が場を和ませる。"}', '{"ラッキーアイテム": "付箋", "ラッキーカラー": "白", "吉方位": "南東", "開運数字": "7"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '中吉', '選択に迷ったら前向きな方を。概ね良い方へ転ぶ。', '{"仕事": "コツコツ型が報われる日。", "学業": "計画通りに進められる日。", "試験": "過去問の復習が当たる。", "対人": "新しい出会いに前向きで吉。"}', '{"ラッキーアイテム": "青いノート", "ラッキーカラー": "緑", "吉方位": "南西", "開運数字": "8"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '中吉', '今日の工夫が明日の余裕を生む。', '{"仕事": "上司に相談すると道が開ける。", "学業": "わからない点を質問して吉。", "試験": "焦らず一問ずつ。十分戦える。", "対人": "誤解は早めの対話で解ける。"}', '{"ラッキーアイテム": "観葉植物", "ラッキーカラー": "金", "吉方位": "北西", "開運数字": "1"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '小吉', '穏やかに前進。背伸びせず等身大で進めば良い。', '{"仕事": "ルーティンを丁寧に。信頼が静かに積もる。", "学業": "復習中心で着実に。", "試験": "基本を落とさなければ及第点。", "対人": "挨拶を欠かさず。好印象が積もる。"}', '{"ラッキーアイテム": "腕時計", "ラッキーカラー": "青", "吉方位": "北", "開運数字": "5"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '小吉', '派手さはないが堅実に積み上がる日。', '{"仕事": "小さなミスに注意すれば問題なし。", "学業": "短時間集中を繰り返すと良い。", "試験": "見直しの時間を確保しよう。", "対人": "聞き上手が信頼を生む。"}', '{"ラッキーアイテム": "名刺入れ", "ラッキーカラー": "橙", "吉方位": "東", "開運数字": "9"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '小吉', '小さな達成を喜ぶことが次の力に。', '{"仕事": "整理整頓が効率を上げる。", "学業": "得意を伸ばして自信をつけよう。", "試験": "緊張しても深呼吸で立て直せる。", "対人": "小さな親切が巡り巡って返る。"}', '{"ラッキーアイテム": "緑茶", "ラッキーカラー": "紫", "吉方位": "南", "開運数字": "2"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '小吉', '焦りは禁物。丁寧さがあなたの武器。', '{"仕事": "焦らず優先順位をつけよう。", "学業": "わからない所に印をつけて後で潰す。", "試験": "得意問題から手をつけて吉。", "対人": "無理に合わせず自然体で。"}', '{"ラッキーアイテム": "ブックカバー", "ラッキーカラー": "銀", "吉方位": "西", "開運数字": "6"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '小吉', '現状維持も立派な前進。土台を固めよう。', '{"仕事": "確認を一手間増やすと安心。", "学業": "基礎固めが今日のテーマ。", "試験": "ケアレスミスにだけ注意。", "対人": "相手の立場を思うと円滑に。"}', '{"ラッキーアイテム": "鉛筆", "ラッキーカラー": "桜色", "吉方位": "北東", "開運数字": "4"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '小吉', 'ちょっとした工夫が効いてくる。', '{"仕事": "地味な作業が後で効く。", "学業": "暗記は少量を反復で。", "試験": "前向きな気持ちが結果を支える。", "対人": "感謝は言葉にして伝えよう。"}', '{"ラッキーアイテム": "印鑑", "ラッキーカラー": "山吹色", "吉方位": "南東", "開運数字": "11"}');
