INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '吉', '可もなく不可もなく、淡々と進めるのが正解。', '{"仕事": "目の前の業務を丁寧に。", "学業": "復習でリズムを取り戻そう。", "試験": "基本問題を確実に。", "対人": "挨拶と笑顔を大切に。"}', '{"ラッキーアイテム": "万年筆", "ラッキーカラー": "紺", "吉方位": "北", "開運数字": "3"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '吉', '目の前のことに集中すれば良い一日に。', '{"仕事": "報連相を欠かさず。", "学業": "計画を見直すと進めやすい。", "試験": "時間配分を意識しよう。", "対人": "聞く姿勢が信頼を生む。"}', '{"ラッキーアイテム": "付箋", "ラッキーカラー": "白", "吉方位": "東", "開運数字": "7"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '吉', '現状を見つめ直す好機。基本に立ち返ろう。', '{"仕事": "整理整頓で効率を保とう。", "学業": "基礎の確認が安心につながる。", "試験": "見直しでミスを防げる。", "対人": "無理せず自然体で。"}', '{"ラッキーアイテム": "青いノート", "ラッキーカラー": "緑", "吉方位": "南", "開運数字": "8"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '吉', '派手な動きより堅実な選択を。', '{"仕事": "無理な約束は避けて吉。", "学業": "短時間でも机に向かう習慣を。", "試験": "落ち着けば実力は出せる。", "対人": "感謝を忘れずに。"}', '{"ラッキーアイテム": "観葉植物", "ラッキーカラー": "金", "吉方位": "西", "開運数字": "1"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '吉', '整える日。机・予定・気持ちを整理しよう。', '{"仕事": "確認作業を大切に。", "学業": "苦手は無理せず少しずつ。", "試験": "得意から解いて流れを作る。", "対人": "相手を尊重すると円滑。"}', '{"ラッキーアイテム": "腕時計", "ラッキーカラー": "青", "吉方位": "北東", "開運数字": "5"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '吉', '小さな一歩で十分。続けることが力に。', '{"仕事": "周囲と歩調を合わせて。", "学業": "得意を磨いて自信に。", "試験": "深呼吸で緊張を和らげて。", "対人": "小さな気遣いが効く。"}', '{"ラッキーアイテム": "名刺入れ", "ラッキーカラー": "橙", "吉方位": "南東", "開運数字": "9"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '吉', '助言に耳を傾けると気づきがある。', '{"仕事": "今日は守りを固める日。", "学業": "睡眠を整えると集中が戻る。", "試験": "準備した範囲を丁寧に。", "対人": "穏やかな対応を心がけて。"}', '{"ラッキーアイテム": "緑茶", "ラッキーカラー": "紫", "吉方位": "南西", "開運数字": "2"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '吉', '焦らなければ流れは悪くない。', '{"仕事": "小さな改善を一つ。", "学業": "焦らず継続を。", "試験": "最後まで諦めないで。", "対人": "焦らず縁を育てよう。"}', '{"ラッキーアイテム": "ブックカバー", "ラッキーカラー": "銀", "吉方位": "北西", "開運数字": "6"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '末吉', '今は種まきの時。すぐ結果が出なくても腐らないで。', '{"仕事": "成果は後からついてくる。今は準備を。", "学業": "基礎固めが後で効く。", "試験": "今回は手応えを掴む練習と捉えて。", "対人": "今は聞き役に徹すると吉。"}', '{"ラッキーアイテム": "鉛筆", "ラッキーカラー": "桜色", "吉方位": "北", "開運数字": "4"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '末吉', 'ゆっくりだが確実に上向く。辛抱が実る。', '{"仕事": "地道な作業を厭わないで。", "学業": "今日わからなくても明日には繋がる。", "試験": "復習の量が次に効いてくる。", "対人": "信頼は時間をかけて育つもの。"}', '{"ラッキーアイテム": "印鑑", "ラッキーカラー": "山吹色", "吉方位": "東", "開運数字": "11"}');
