INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '末吉', '焦りは禁物。基礎を固める時期と心得て。', '{"仕事": "目立たなくても評価は蓄積中。", "学業": "コツコツ型が最後に伸びる。", "試験": "結果に一喜一憂しないで。", "対人": "感謝を言葉にして関係を温めて。"}', '{"ラッキーアイテム": "万年筆", "ラッキーカラー": "紺", "吉方位": "北東", "開運数字": "3"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '末吉', '小さな前進を見逃さないで。確かに進んでいる。', '{"仕事": "報連相で信頼を貯めよう。", "学業": "計画を小さく刻んで継続を。", "試験": "時間配分の練習を重ねよう。", "対人": "誤解は丁寧な説明で解ける。"}', '{"ラッキーアイテム": "付箋", "ラッキーカラー": "白", "吉方位": "南東", "開運数字": "7"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '末吉', '今日の我慢が明日の余裕に変わる。', '{"仕事": "小さな改善を続けて。", "学業": "苦手と向き合う好機。", "試験": "あと少しの粘りが鍵。", "対人": "無理に広げず深めよう。"}', '{"ラッキーアイテム": "青いノート", "ラッキーカラー": "緑", "吉方位": "南西", "開運数字": "8"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '末吉', '遠回りに見える道が一番の近道になることも。', '{"仕事": "次のチャンスに備えて整える。", "学業": "焦らず土台を作ろう。", "試験": "準備を積めば必ず報われる。", "対人": "誠実さが後で実を結ぶ。"}', '{"ラッキーアイテム": "観葉植物", "ラッキーカラー": "金", "吉方位": "北西", "開運数字": "1"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '凶', '今日は守りの日。新しい挑戦より確認を優先して。', '{"仕事": "ダブルチェックを徹底しよう。", "学業": "新範囲より復習に充てよう。", "試験": "見直しを最優先に。", "対人": "言葉選びは慎重に。"}', '{"ラッキーアイテム": "腕時計", "ラッキーカラー": "青", "吉方位": "北", "開運数字": "5"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '凶', '無理は禁物。一度立ち止まって見直そう。', '{"仕事": "大きな決断は先送りが無難。", "学業": "詰め込みは逆効果。休憩を挟んで。", "試験": "難問は飛ばして取れる所から。", "対人": "感情的な返信は一晩おいて。"}', '{"ラッキーアイテム": "名刺入れ", "ラッキーカラー": "橙", "吉方位": "東", "開運数字": "9"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '凶', '焦るとミスが出やすい。ゆっくり丁寧に。', '{"仕事": "報連相を丁寧に、独断は避けて。", "学業": "わからない所は印だけつけて先へ。", "試験": "ケアレスミスに最大の注意を。", "対人": "誤解が生じやすい日。確認を丁寧に。"}', '{"ラッキーアイテム": "緑茶", "ラッキーカラー": "紫", "吉方位": "南", "開運数字": "2"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '凶', 'うまくいかなくても自分を責めないで。', '{"仕事": "締切に余裕を持って動こう。", "学業": "睡眠不足に注意。整える日。", "試験": "緊張したら深呼吸で立て直して。", "対人": "無理な付き合いは断っても良い。"}', '{"ラッキーアイテム": "ブックカバー", "ラッキーカラー": "銀", "吉方位": "西", "開運数字": "6"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '凶', '小さなトラブルに注意。早めの対処が吉。', '{"仕事": "ミスは早めに報告すれば傷が浅い。", "学業": "計画は無理せず軽めに。", "試験": "時間配分を守れば致命傷は避けられる。", "対人": "聞き役に回ると波風が立たない。"}', '{"ラッキーアイテム": "鉛筆", "ラッキーカラー": "桜色", "吉方位": "北東", "開運数字": "4"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '凶', '休息も戦略のうち。今日は充電に充てて。', '{"仕事": "新規より既存業務の整理を。", "学業": "焦りは禁物。基礎の確認を。", "試験": "完璧を狙わず確実に部分点を。", "対人": "距離を取ることも優しさ。"}', '{"ラッキーアイテム": "印鑑", "ラッキーカラー": "山吹色", "吉方位": "南東", "開運数字": "11"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '凶', '他人と比べず、自分のペースを守ろう。', '{"仕事": "無理な引き受けは控えて。", "学業": "短時間でもやれば十分。", "試験": "終わったことより次に集中。", "対人": "謝るべき時は素直に。"}', '{"ラッキーアイテム": "しおり", "ラッキーカラー": "藍", "吉方位": "南西", "開運数字": "21"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '凶', '種まきの前の整地と考えれば気が楽に。', '{"仕事": "今日は守りを固める日。", "学業": "自分を責めず一歩だけ進めて。", "試験": "準備した範囲だけは丁寧に。", "対人": "今日は自分を労わって。"}', '{"ラッキーアイテム": "白いハンカチ", "ラッキーカラー": "若草色", "吉方位": "北西", "開運数字": "24"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '大凶', '底を打てば後は上がるだけ。今日は何もしないが正解の日も。', '{"仕事": "重要判断・契約は絶対に先送り。", "学業": "新しいことは始めず復習だけに。", "試験": "結果に過度な期待をせず、経験として臨んで。", "対人": "今日は連絡・返信を控えめに。"}', '{"ラッキーアイテム": "万年筆", "ラッキーカラー": "紺", "吉方位": "北", "開運数字": "3"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '大凶', 'うまくいかなくて当然。自分を責めず休もう。', '{"仕事": "ミスが出やすい。確認を何重にも。", "学業": "詰め込みは禁物。しっかり休もう。", "試験": "取れる問題だけ確実に。", "対人": "口論は避けて距離を取ろう。"}', '{"ラッキーアイテム": "付箋", "ラッキーカラー": "白", "吉方位": "東", "開運数字": "7"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '大凶', '大きな動きは厳禁。現状維持で嵐をやり過ごそう。', '{"仕事": "新規案件は受けない方が無難。", "学業": "体調最優先。睡眠を確保して。", "試験": "難問は潔く飛ばそう。", "対人": "感情的な言葉は飲み込んで。"}', '{"ラッキーアイテム": "青いノート", "ラッキーカラー": "緑", "吉方位": "南", "開運数字": "8"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '大凶', '今日の停滞は明日の飛躍の助走。焦らないで。', '{"仕事": "トラブルは抱えず早めに相談を。", "学業": "焦って手を広げない。", "試験": "緊張が強い日。深呼吸を何度も。", "対人": "無理な集まりは欠席でも良い。"}', '{"ラッキーアイテム": "観葉植物", "ラッキーカラー": "金", "吉方位": "西", "開運数字": "1"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '大凶', '心と体を最優先に。無理だけは避けて。', '{"仕事": "今日は最低限の業務に絞って。", "学業": "わからなくても今日は気にしない。", "試験": "ミスしても引きずらないで。", "対人": "一人の時間を大切に。"}', '{"ラッキーアイテム": "腕時計", "ラッキーカラー": "青", "吉方位": "北東", "開運数字": "5"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '大凶', '失敗しても経験値は確実に増えている。', '{"仕事": "無理な残業は避けて休もう。", "学業": "机に向かえただけで十分。", "試験": "終わった科目は振り返らず次へ。", "対人": "誤解は後日落ち着いてから解こう。"}', '{"ラッキーアイテム": "名刺入れ", "ラッキーカラー": "橙", "吉方位": "南東", "開運数字": "9"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '大凶', '悪い流れは長くは続かない。耐える日と心得て。', '{"仕事": "守りに徹すれば傷は最小に。", "学業": "明日への充電日と考えて。", "試験": "完答より部分点狙いで十分。", "対人": "誰かに頼ることは弱さではない。"}', '{"ラッキーアイテム": "緑茶", "ラッキーカラー": "紫", "吉方位": "南西", "開運数字": "2"}');
INSERT INTO omikuji (jinjya, fortune, message, tags, extra) VALUES ('joju', '大凶', '一度すべて手放して、明日仕切り直そう。', '{"仕事": "嵐が過ぎるのを静かに待とう。", "学業": "自分を責めないことが一番大事。", "試験": "次への課題を一つ持ち帰れれば収穫。", "対人": "まず自分を守ることを優先して。"}', '{"ラッキーアイテム": "ブックカバー", "ラッキーカラー": "銀", "吉方位": "北西", "開運数字": "6"}');
